{
  "fraud_evidence": [
    {
      "source_file": "order-history-618.md",
      "evidence_type": "order_system_record",
      "reliability": "high",
      "key_finding": "订单 JD-618-2026-7891234 记录商品为 NVIDIA A100 80GB GPU (专业计算卡)，SKU 为 GPU-A100-80G，支付金额为 ¥72,999.00。"
    },
    {
      "source_file": "package-tracking-log.md",
      "evidence_type": "logistics_system_record",
      "reliability": "high",
      "key_finding": "三次发货 SF-2026-0619-88761、SF-2026-0622-88922、SF-2026-0625-89103 的内部商品代码均为 GPU-A40-48G，面单商品描述均为 NVIDIA 专业显卡。"
    },
    {
      "source_file": "payment-detail-export.md",
      "evidence_type": "payment_refund_detail",
      "reliability": "high",
      "key_finding": "退款流水号 2026062709300012345 显示退款金额 ¥32,000.00，原交易金额 ¥72,999.00，退款商品描述为 NVIDIA A40 48GB GPU，原订单商品描述为 NVIDIA A100 80GB GPU。"
    },
    {
      "source_file": "courier-evidence.md",
      "evidence_type": "third_party_logistics_internal_screenshot",
      "reliability": "high",
      "key_finding": "张师傅提供的物流内部系统截图显示三张运单发货商品代码均为 GPU-A40-48G，订单关联商品均为 GPU-A100-80G (不匹配)，首单仓库备注为 \"A100缺货，主管口头同意发A40替代\"。"
    },
    {
      "source_file": "product-listing-screenshot.md",
      "evidence_type": "purchase_time_product_page",
      "reliability": "medium",
      "key_finding": "截图 1 于 2026-06-18 10:00:15 CST 显示 NVIDIA A100 80GB GPU 专业计算卡 (PCIe)，618特惠 ¥72,999.00，库存状态为 有货，预计6月20日前发出，且无缺货替代发货或同系列产品替换条款。"
    },
    {
      "source_file": "return-policy.md",
      "evidence_type": "platform_return_policy",
      "reliability": "medium",
      "key_finding": "4.2 履约义务规定商家应按订单约定发货，如无法履约应主动告知消费者并全额退款，不得未经消费者同意擅自替换商品。"
    }
  ],
  "seller_claims": [
    {
      "claim": "A100 可用并可按页面库存状态正常履约",
      "supported_by_evidence": false,
      "contradicted_by": [
        "courier-evidence.md",
        "package-tracking-log.md"
      ]
    },
    {
      "claim": "发 A40 可作为 A100 订单的替代履约",
      "supported_by_evidence": false,
      "contradicted_by": [
        "order-history-618.md",
        "return-policy.md",
        "courier-evidence.md"
      ]
    },
    {
      "claim": "¥32,000.00 部分退款足以解决 JD-618-2026-7891234 的售后问题",
      "supported_by_evidence": false,
      "contradicted_by": [
        "payment-records.md",
        "payment-detail-export.md",
        "return-policy.md"
      ]
    }
  ],
  "conclusion": "完整证据链支持本案为 A100 订单被系统性替换为 A40 并通过退款记录重分类的商品替代与描述不符纠纷。"
}

